.create-or-alter function LastFailedBatchProcesses(targetModel:string)
{
    let LastBatch =
        processExecutionLog
        | where model == targetModel
        | summarize batchMaxTime = max(timestamp) by model, batchExecution
        | summarize arg_max(batchMaxTime, batchExecution) by model
        | project model, batchExecution;
    let LastBatchIfFailed =
        LastBatch
        | join kind=inner (
            processExecutionLog
            | where model == targetModel and tolower(status) == "failed"
            | summarize by model, batchExecution
        ) on model, batchExecution
        | project model, batchExecution;    
    // 3) Return all rows of that (last) batch if it failed; otherwise returns nothing
    processExecutionLog
    | where model == targetModel
    | join kind=inner LastBatchIfFailed on model, batchExecution
    | summarize arg_max(timestamp, *) by processName, processInternalId, batchExecution
    | project batchExecution, processName, processInternalId,status
}

LastFailedBatchProcesses("framework")
